html:
{%- set no_default_print_heading = 1 -%}
{%- from "templates/print_formats/standard_macros.html" import add_header -%}

<div class="main-container">
  {{ add_header(0, 1, doc, letter_head, no_letterhead, print_settings) }}

  <style>
  {%- set border_inset = 0 -%}
  {%- set content_inner_padding = 3 -%}

  html, body { margin:0; padding:0; height:100%; font-family: Arial, sans-serif; font-size: 13px; }

  .letter-head img,
  .letter-head .logo,
  .letter-head .logo img,
  .header-logo img,
  .company-logo img {
    max-width: 160px !important;
    max-height: 90px !important;
    width: auto !important;
    height: auto !important;
    object-fit: contain !important;
    display: inline-block !important;
  }

  .print-format {
    position:relative;
    background:transparent !important;
    margin:0 !important;
    padding:0;
    font-family: Arial, sans-serif;
    font-size: 13px;
  }

  .page-border {
    position:fixed;
    top:{{ border_inset }}mm;
    left:{{ border_inset }}mm;
    right:{{ border_inset }}mm;
    bottom:{{ border_inset }}mm;
    border:1px solid #000;
    z-index:0;
    pointer-events:none;
  }

  .main-container {
    position:relative;
    z-index:1;
    padding:{{ content_inner_padding }}mm;
    font-family: Arial, sans-serif;
    font-size: 13px;
  }

  .print-heading,
  .print-heading + div { display:none !important; }

  .heading-label {
    font-size:18px;
    font-weight:600;
    text-align:center;
    color:#222;
    margin-bottom:2px;
    letter-spacing:1px;
    text-transform:uppercase;
    font-family: Arial, sans-serif;
  }

  .sub-heading {
    font-size:13px;
    font-weight:500;
    text-align:center;
    color:#333;
    margin-bottom:12px;
    font-family: Arial, sans-serif;
  }

  .section { margin-bottom:10px; }

  .section-title {
    font-size:13px;
    font-weight:600;
    border-bottom:1px solid #000;
    color:#000;
    margin-bottom:4px;
    padding-bottom:1px;
    font-family: Arial, sans-serif;
  }

  .letter-head {
    margin-bottom:2mm !important;
  }

  .matrix-table {
    width:100%;
    border-collapse:collapse;
    table-layout:fixed;
  }

  .matrix-table th {
    background:#fff;
    color:#000;
    border-bottom:1px solid #000;
    border-top:1px solid #000;
    padding:6px 8px;
    font-weight:700;
    font-size:12px;
    text-align:right;
    word-break:break-word;
    font-family: Arial, sans-serif;
    vertical-align:bottom;
  }

  .matrix-table tbody td {
    padding:10px 8px;
    font-size:14px;
    font-weight:600;
    text-align:right;
    border-top:2px solid #000;
    border-bottom:2px solid #000;
    white-space:nowrap;
    font-family: Arial, sans-serif;
  }

  .total-col {
    border-left:2px solid #000 !important;
    font-weight:700 !important;
    background:#f9f9f9;
  }

  .rt { text-align:right; }

  .notes-box {
    border:1px solid #333;
    min-height:60px;
    padding:8px;
    font-size:13px;
    font-family:Arial,sans-serif;
    white-space:pre-wrap;
  }

  .signatures { width:100%; margin-top:28px; border-collapse:collapse; }
  .signatures td { width:33.33%; padding:0 14px; text-align:center; }
  .sig-line { border-top:1px solid #111; padding-top:6px; font-size:13px; }

  .footer-note {
    font-size:11px;
    color:#555;
    text-align:center;
    margin-top:8px;
    font-family: Arial, sans-serif;
  }
  </style>

  <div class="page-border"></div>

  <div class="heading-label">Weekly Cash Statement Balance</div>
  <div class="sub-heading">{{ doc.company }} &nbsp;|&nbsp; Week Ending: {{ frappe.utils.formatdate(doc.week_ending_date, 'EEEE, dd MMMM yyyy') }}</div>

  {%- set currency = frappe.db.get_value("Company", doc.company, "default_currency") or "" -%}
  {%- set total = namespace(val=0) -%}
  {%- for row in doc.balances -%}
    {%- set total.val = total.val + (row.statement_balance or 0) -%}
  {%- endfor -%}

  <!-- Account Balances Matrix -->
  <div class="section">
    <div class="section-title">Account Balances</div>
    <table class="matrix-table">
      <thead>
        <tr>
          {% for row in doc.balances %}
          <th>{{ row.account }}</th>
          {% endfor %}
          <th class="total-col">TOTAL</th>
        </tr>
      </thead>
      <tbody>
        <tr>
          {% for row in doc.balances %}
          <td class="rt">{{ frappe.utils.fmt_money(row.statement_balance or 0, currency=currency) }}</td>
          {% endfor %}
          <td class="rt total-col">{{ frappe.utils.fmt_money(total.val, currency=currency) }}</td>
        </tr>
      </tbody>
    </table>
  </div>

  {% if doc.notes %}
  <!-- Notes -->
  <div class="section" style="margin-top:14px;">
    <div class="section-title">Notes</div>
    <div class="notes-box">{{ doc.notes }}</div>
  </div>
  {% endif %}

  <!-- Signatures -->
  <div class="section" style="margin-top:20px;">
    <table class="signatures">
      <tr>
        <td><div class="sig-line">Prepared By</div></td>
        <td><div class="sig-line">Checked By</div></td>
        <td><div class="sig-line">Approved By</div></td>
      </tr>
    </table>
  </div>

  <div class="footer-note">
    Printed on: {{ frappe.utils.format_datetime(frappe.utils.now_datetime(), 'dd-MMM-yyyy HH:mm:ss') }}
  </div>
</div>
